import{_ as t,o as n,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"4. Definitions","description":"","frontmatter":{"title":"4. Definitions","eba":"Biomedical Engineers 2025-2028","topics":["leave","hours"]},"headers":[],"relativePath":"ebas/biomedical-engineers/preliminary/4-definitions.md","filePath":"ebas/biomedical-engineers/preliminary/4-definitions.md"}'),a={name:"ebas/biomedical-engineers/preliminary/4-definitions.md"};function r(s,e,p,l,g,d){return n(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_4-definitions" tabindex="-1">4. Definitions <a class="header-anchor" href="#_4-definitions" aria-label="Permalink to &quot;4. Definitions&quot;">​</a></h1><p><strong>4.1</strong> Act means the Fair Work Act 2009 (Cth), or its successor.</p><p><strong>4.2</strong> Agreement means the Biomedical Engineers (Victorian Public Sector) (Single Interest Employers) Enterprise Agreement 2024-2028.</p><p><strong>4.3</strong> Child includes an adopted child, step child and ex-nuptial child.</p><p><strong>4.4</strong> Commission means the Fair Work Commission or any successor body.</p><p><strong>4.5</strong> Employee means a person employed by an Employer listed in <a href="/eba/ebas/allied-health/appendices/1-list-of-employers.html">Appendix 1</a> of this Agreement who is qualified to carry out Professional Engineering Duties and is employed to apply engineering method to the solution of problems in the area of medicine and other life sciences (Biomedical Engineer).</p><p><strong>4.6</strong> Employer means each organisation listed in <a href="/eba/ebas/allied-health/appendices/1-list-of-employers.html">Appendix 1</a> of this Agreement.</p><p><strong>4.7</strong> Experienced Engineer means a professional engineer with the undermentioned qualifications engaged in any particular employment where the adequate discharge of any portion of the duties requires qualifications of the employee as (or at least equal to those of) a member of Engineers Australia. The qualifications are as follows:</p><p><strong>(a)</strong> membership of Engineers Australia; or</p><p><strong>(b)</strong> having graduated in a four or five year course at a university recognised by Engineers Australia, four years’ experience on professional engineering duties since becoming a Qualified Engineer; or</p><p><strong>(c)</strong> not having so graduated, five years of such experience. Note: An experienced engineer with 5 years’ experience must still hold a three-year engineering degree or equivalent diploma.</p><p><strong>4.8</strong> FFPPOA means the first full pay period on or after.</p><p><strong>4.9</strong> HSR means a health and safety representative (including a deputy health and safety representative).</p><p><strong>4.10</strong> Immediate Family means:</p><p><strong>(a)</strong> a Spouse, Child, parent, grandparent, grandchild or sibling of the Employee; or</p><p><strong>(b)</strong> a child, parent, grandparent, grandchild or sibling of a Spouse of the Employee.</p><p><strong>4.11</strong> National Employment Standards or NES means Part 2-2 of the Act as amended from time to time.</p><p><strong>4.12</strong> OHS Act means the Occupational Health and Safety Act 2004 (Vic), or its successor.</p><p><strong>4.13</strong> Professional Engineering Duties shall mean duties carried out by a person, in their particular employment, the adequate discharge of any portion of their duties requires the Employee to hold qualifications (or of at least equal to those of) a Graduate member of the Institute of Engineers Australia.</p><p><strong>4.14</strong> Qualified Engineer shall mean a Biomedical Engineer who is or is qualified to become a Graduate member of the Institute of Engineers Australia.</p><p><strong>4.15</strong> Reasonable Business Grounds include but are not limited to the request / proposal (however titled) being the following:</p><p><strong>(a)</strong> too costly for the employer;</p><p><strong>(b)</strong> that there is no capacity to change the working arrangements of other employees to accommodate;</p><p><strong>(c)</strong> that it would be impractical to change the working arrangements of other employees, or recruit new employees, to accommodate</p><p><strong>(d)</strong> likely to result in a significant loss in efficiency or productivity;</p><p><strong>(e)</strong> likely to have a significant negative impact on customer service.</p><p><strong>4.16</strong> Registered Health Practitioner means an individual who is registered under the Health Practitioner Regulation National Law (as adopted in the applicable State or Territory) to practice a health profession, other than as a student.</p><p><strong>4.17</strong> Regulations means the Fair Work Regulations 2009 (Cth), or its successor.</p><p><strong>4.18</strong> Spouse includes a person to whom an Employee is married, a de facto partner, former spouse, or former de facto partner of the Employee. A de facto partner means a person who, although not legally married to the Employee, lives with the Employee in a relationship as a couple (whether the same sex or different sexes) on a genuine domestic basis.</p><p><strong>4.19</strong> Stillborn or Stillborn Child means:</p><p><strong>(a)</strong> a child who weighs at least 400 grams at delivery or whose period of gestation was at least 20 weeks; and</p><p><strong>(b)</strong> who has not breathed since delivery; and</p><p><strong>(c)</strong> whose heart has not beaten since delivery.</p><p><strong>4.20</strong> Union means the Association of Professional Engineers, Scientists and Managers, Australia trading as Professionals Australia.</p><p><strong>4.21</strong> VHIA means the Employer’s Representative, the Victorian Hospitals’ Industrial Association.</p><p><strong>4.22</strong> WIRC Act means the Workplace Injury Rehabilitation and Compensation Act 2013 (Vic), or if applicable in the particular situation the Accident Compensation Act 1985 (Vic) or the Workers Compensation Act 1958 (Vic).</p><p><strong>4.23</strong> 2022 Agreement means the Biomedical Engineers (Victorian Public Sector) Enterprise Agreement 2022-2023.</p><p>Plain language terms: glossary, meanings.</p>',38)])])}const m=t(a,[["render",r]]);export{h as __pageData,m as default};
